const msg = $json.message?.text || '';
const userId = $json.message?.from?.id;

// Match /rate N or ⭐ count (1-5)
const rateMatch = msg.match(/\/rate\s+([1-5])/i) || msg.match(/(⭐{1,5})/);
if (!rateMatch) return null; // not a feedback message

let score;
if (rateMatch[1] && /^[1-5]$/.test(rateMatch[1])) {
  score = parseInt(rateMatch[1]);
} else if (rateMatch[1]) {
  score = rateMatch[1].length; // count stars
}

const flagged = score < 3;
return {
  score,
  flagged,
  user_id: userId,
  raw_message: msg,
  is_feedback: true
};

