INSERT INTO task_board (pillar, task_desc, assigned_agent, status, feedback_score, created_at)
VALUES ('FEEDBACK', 'User rating: {{ $json.score }}/5', 'jeff', CASE WHEN {{ $json.flagged }} THEN 'flagged' ELSE 'ok' END, {{ $json.score }}, NOW())
RETURNING id, feedback_score, status;
